class ElasticsearchLogHandler(logging.Handler):
    def __init__(
        self,
        app: ElasticsearchApp,
        level: int = logging.INFO,
        service: Optional[str] = None,
        environment: Optional[str] = None,
    ) -> None:
        super().__init__(level=level)
        self.app = app
        self.service = service or app.app_name
        self.environment = environment or os.getenv("APP_ENV", "development")

    def emit(self, record: logging.LogRecord) -> None:
        try:
            message = self.format(record)
            exception_text = None
            if record.exc_info:
                exception_text = self.formatException(record.exc_info) if hasattr(self, "formatException") else str(record.exc_info)

            fields = {
                "module": record.module,
                "funcName": record.funcName,
                "lineno": record.lineno,
                "process": record.process,
                "thread": record.thread,
                "pathname": record.pathname,
            }

            trace_id = getattr(record, "trace_id", None)

            self.app.log_event(
                level=record.levelname,
                message=message,
                logger_name=record.name,
                service=self.service,
                environment=self.environment,
                trace_id=trace_id,
                exception=exception_text,
                fields=fields,
                timestamp=datetime.fromtimestamp(record.created, tz=timezone.utc).isoformat(),
            )
        except Exception:
            self.handleError(record)


def configure_python_logger(app: ElasticsearchApp, logger_name: str = "platform") -> logging.Logger:
    logger = logging.getLogger(logger_name)
    logger.setLevel(logging.INFO)

    if not any(isinstance(h, ElasticsearchLogHandler) for h in logger.handlers):
        es_handler = ElasticsearchLogHandler(app=app)
        formatter = logging.Formatter("%(asctime)s %(name)s %(levelname)s %(message)s")
        es_handler.setFormatter(formatter)
        logger.addHandler(es_handler)

    if not any(isinstance(h, logging.StreamHandler) for h in logger.handlers):
        stream_handler = logging.StreamHandler(sys.stdout)
        stream_handler.setFormatter(logging.Formatter("%(asctime)s %(name)s %(levelname)s %(message)s"))
        logger.addHandler(stream_handler)

    return logger


def demo(app: ElasticsearchApp) -> None:
    app.setup_indices()

    app.index_document(
        title="Elasticsearch Full Text Search",
        content="Elasticsearch provides distributed, RESTful search and analytics.",
        tags=["search", "elasticsearch", "analytics"],
        author="admin",
        metadata={"category": "guide"},
    )

    app.bulk_index_documents(
        [
            {
                "title": "Centralized Logging Platform",
                "content": "Use Elasticsearch to store and search application logs across services.",
                "tags": ["logging", "observability"],
                "author": "ops",
                "metadata": {"team": "platform"},
            },
            {
                "title": "Python Elasticsearch Client",
                "content": "The elasticsearch-py library allows indexing, searching, and aggregations.",
                "tags": ["python", "client", "elasticsearch"],
                "author": "developer",
                "metadata": {"language": "python"},
            },
        ]
    )

    search_result = app.search_documents(query="Elasticsearch search")
    print(json.dumps(search_result.body if hasattr(search_result, "body") else search_result, indent=2, default=str))

    logger = configure_python_logger(app, "centralized.logging")
    logger.info("Application started")
    logger.warning("A sample warning for aggregation testing")
    try:
        raise RuntimeError("Simulated processing failure")
    except RuntimeError:
        logger.exception("An example exception event")

    app.bulk_log_events(
        [
            {
                "level": "INFO",
                "logger": "auth-service",
                "message": "User login successful",
                "service": "auth-service",
                "environment": "development",
                "fields": {"user_id": "u-1001"},
            },
            {
                "level": "ERROR",
                "logger": "billing-service",
                "message": "Payment processing failed",
                "service": "billing-service",
                "environment": "development",
                "exception": "Card declined",
                "fields": {"order_id": "o-2001"},
            },
        ]
    )

    logs_result = app.search_logs(query="failed", level=["ERROR", "WARNING", "INFO"])
    print(json.dumps(logs_result.body if hasattr(logs_result, "body") else logs_result, indent=2, default=str))

    agg_result = app.aggregate_logs(interval="1h")
    print(json.dumps(agg_result.body if hasattr(agg_result, "body") else agg_result, indent=2, default=str))


def main() -> None:
    app = ElasticsearchApp(hosts=DEFAULT_ELASTIC_URL)

    if not app.ping():
        raise ConnectionError(f"Could not connect to Elasticsearch at {DEFAULT_ELASTIC_URL}")

    demo(app)


if __name__ == "__main__":
    main()